import{_ as r,o as a,c as o,a5 as t}from"./chunks/framework.DJpSEDx_.js";const p=JSON.parse('{"title":"Service consumer","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/personas/service-consumer.md","filePath":"concepts/personas/service-consumer.md"}'),i={name:"concepts/personas/service-consumer.md"};function n(s,e,c,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="service-consumer" tabindex="-1">Service consumer <a class="header-anchor" href="#service-consumer" aria-label="Permalink to &quot;Service consumer&quot;">​</a></h1><p>Service consumers use Platform Mesh to discover, order, and manage service capabilities. They work with declarative resources in their own account workspaces instead of learning every provider&#39;s runtime and operational interface.</p><p>Consumers include developers, data scientists, application owners, and any team that needs to use a capability — a database, a certificate, a Kubernetes cluster, an AI inference endpoint — without operating it themselves.</p><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Consume services through a consistent Kubernetes Resource Model interface, with clear ownership boundaries between consumer intent and provider implementation.</p><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h2><ul><li>Discover available service APIs.</li><li>Bind provider APIs into the consumer account workspace when required.</li><li>Create and update desired-state resources for service instances.</li><li>Observe lifecycle status and act on failures or required follow-up.</li><li>Integrate consumed services into applications, GitOps flows, or automation.</li></ul><h2 id="ownership-boundary" tabindex="-1">Ownership boundary <a class="header-anchor" href="#ownership-boundary" aria-label="Permalink to &quot;Ownership boundary&quot;">​</a></h2><p>The consumer owns the <strong>request</strong> — the desired-state resources in their account workspace and the application code that uses the resulting capability. They do not own the provider runtime or the underlying service implementation. The control plane mediates everything in between: the consumer writes spec, the provider writes status, and Platform Mesh delivers each side to the other across the account boundary.</p><h2 id="interaction-modes" tabindex="-1">Interaction modes <a class="header-anchor" href="#interaction-modes" aria-label="Permalink to &quot;Interaction modes&quot;">​</a></h2><p>Consumers can interact with their workspace through different surfaces, all of which work against the same Kubernetes Resource Model:</p><ul><li>The Platform Mesh Portal for graphical discovery and management.</li><li><code>kubectl</code> and standard Kubernetes tooling for command-line workflows.</li><li>GitOps tools (Flux, Argo CD) and IaC tools (Terraform) for declarative, version-controlled workflows.</li></ul><p>The choice of surface does not change the underlying API or the ownership boundary.</p><h2 id="common-questions" tabindex="-1">Common questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common questions&quot;">​</a></h2><ul><li>Which services are available to my account?</li><li>How do I bind or consume a provider API?</li><li>Which resources do I create to request a service instance?</li><li>Where do I check status and failure information?</li><li>Can I use <code>kubectl</code>, GitOps, IaC, or the portal for this workflow?</li></ul><h2 id="recommended-reading" tabindex="-1">Recommended reading <a class="header-anchor" href="#recommended-reading" aria-label="Permalink to &quot;Recommended reading&quot;">​</a></h2><p>Start with <a href="/pr-preview/pr-179/tutorials/explore-example-msp.html">Explore the example MSP</a> for a guided walkthrough of the consumer experience. Then read <a href="./../interaction-patterns/provider-to-consumer.html">Interaction patterns</a> to understand how providers and consumers connect, <a href="./../account-model.html">Account model</a> for how consumer accounts are structured, and <a href="./../api-sharing.html">API sharing</a> for how provider APIs become available in the consumer workspace.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../account-model.html">Account model</a></li><li><a href="./../api-sharing.html">API sharing</a></li><li><a href="/pr-preview/pr-179/reference/components/portal.html">Portal</a></li><li><a href="/pr-preview/pr-179/reference/components/marketplace.html">Marketplace</a></li></ul>',19)])])}const m=r(i,[["render",n]]);export{p as __pageData,m as default};
